import { AxiosPromise, AxiosRequestConfig } from 'axios';
import { collectdistAxiosClient, CommonSuccessResponse } from "@komca-dev-org/komca-frontend-common-lib";

/**
 * 거래처계약을 삭제합니다. \n\n**주의:** 이 작업을 실행하면 데이터가 복구되지 않습니다.
 */
export function deleteBscon(params: Params, config: AxiosRequestConfig = {}): AxiosPromise<ResponseData> {
  const { contrNo} = params;
  const { params: configParams, ...restConfig } = config;

  return collectdistAxiosClient.post<ResponseData>(`/api/v1/levy/contr/bscon/delete/${contrNo}`, {
    ...restConfig
  });
}

interface Params {
  contrNo: string;
}

interface ResponseData extends CommonSuccessResponse<void> {
}

