public int processDeleteApprvCascade(String contrNo, String apprvNo) {
        BsconApprvDeleteRequest apprvDeleteReq = BsconApprvDeleteRequest.builder()
            .contrNo(contrNo)
            .apprvNo(apprvNo)
            .build();

        // 이용허락내역 삭제
        int deleteCount = bsconCommandMapper.deleteBsconApprv(apprvDeleteReq);

        if( deleteCount > 0 ) {
            // 사용승인제출서류 삭제
            bsconCommandMapper.deleteBsconApprvPropDoc(apprvDeleteReq);

            // 정산내역 삭제
            bsconCommandMapper.deleteBsconClrRec(apprvDeleteReq);

            // 사용저작물 삭제
            bsconCommandMapper.deleteBsconUseTune(apprvDeleteReq);

            // 권리자 발생금액 삭제
            bsconCommandMapper.deleteBsconRightpersOccAmt(apprvDeleteReq);

            // 신청자 정보 삭제
            bsconCommandMapper.deleteBsconApptnpers(apprvDeleteReq);
        }

        return deleteCount;
    }

    /**
     * 거래처 계약 생성
     */
    @Override
    @Transactional(rollbackFor = Exception.class)

