/**
 * 정산-전송 곡별지분충돌 REST API Controller
 */
@RequiredArgsConstructor
@RestController("levyClrSendConflictController")
@RequestMapping("/api/v1/levy/clr/send/conflict")
@Validated
public class ConflictController implements ConflictApi {

    private final ConflictCommandService conflictCommandService;
    private final ConflictQueryService conflictQueryService;

    /**
     * 곡별지분충돌 목록 조회
     */
    @Override
    @GetMapping
    public ResponseEntity<CommonSuccessResponse<ListResponse<ConflictList>>> getConflictList(
            @ModelAttribute @Validated ConflictListSearch request) {
        return CommonSuccessResponse.ok(conflictQueryService.getConflictList(request));
    }

    /**
     * 곡별지분충돌 목록 조회 (엑셀)
     */
    @Override
    @GetMapping("/excel")
    public ResponseEntity<CommonSuccessResponse<ListResponse<ConflictExcelList>>> getConflictExcelList(
            @ModelAttribute @Validated ConflictListSearch request) {
        return CommonSuccessResponse.ok(conflictQueryService.getConflictExcelList(request));
    }

    /**
     * 곡별지분충돌 목록 엑셀 파일을 파싱하여 DB에 데이터 등록
     */
    @Override
    @PostMapping("/imports/excel")
    public ResponseEntity<CommonSuccessResponse<ConflictImportExcelCreate>> createConflictImportExcel(
            @Validated @RequestBody ConflictImportExcelCreateRequest request) {
        return CommonSuccessResponse.created(conflictCommandService.createConflictImportExcel(request));
    }

    /**
     * 곡별지분충돌 공개 상태 업데이트
     */
    @Override
    @PostMapping("/open/update")
    public ResponseEntity<CommonSuccessResponse<ConflictOpenUpdate>> updateOpenConflict(
            @Validated @RequestBody ConflictOpenUpdateRequest request) {
