import { AxiosPromise, AxiosRequestConfig } from 'axios';
import { collectdistAxiosClient, CommonSuccessResponse, PageListResponse } from "@komca-dev-org/komca-frontend-common-lib";
import { ModalContrList, ModalContrListSearch } from '@/network';
import {buildHelpers} from "@/pages/collect/contract/license_application/utils";

/**
 * 계약정보 목록을 조회합니다.
 */
export function getModalContrList(params: Params, config: AxiosRequestConfig = {}): AxiosPromise<ResponseData> {
  const { ...restParams } = params;
  const { params: configParams, ...restConfig } = config;

  return collectdistAxiosClient.get<ResponseData>(`/api/v1/mng/comm/modal/contr`, {
    ...restConfig,
    params: {
      ...restParams,
      contrStartDay: buildHelpers.formatDate(restParams.contrStartDay),
      contrEndDay: buildHelpers.formatDate(restParams.contrEndDay),
      contrExpireDay: buildHelpers.formatDate(restParams.contrExpireDay),
      ...configParams,
    },
  });
}

interface Params extends ModalContrListSearch {
  // ModalContrListSearch에서 상속받은 파라미터 사용
}

interface ResponseData extends CommonSuccessResponse<PageListResponse<ModalContrList>> {
}

